from functools import lru_cache


class Solution:
    def maxOperations(self, s):
        @lru_cache(maxsize=None)
        def rec(t):
            best = 0
            for i in range(len(t) - 1):
                if t[i] == '1' and t[i + 1] == '0':
                    j = i + 1
                    while j + 1 < len(t) and t[j + 1] == '0':
                        j += 1
                    nt = t[:i] + t[i + 1:j + 1] + '1' + t[j + 1:]
                    best = max(best, 1 + rec(nt))
            return best
        result = rec(s)
        rec.cache_clear()
        return result

